@app.route('/posts/<int:post_id>', methods=['DELETE'])
@login_required
def delete_post(post_id):
    """
    Delete a post belonging to the currently authenticated user.

    Security measures:
    1. @login_required ensures the user is authenticated.
    2. The query is scoped to the current user's ID (tenant/owner scoping),
       so a user cannot delete another user's post even if they know the post ID.
    3. If no matching post is found (wrong ID or not owned by current user),
       a generic 404 is returned to avoid leaking information about other users' posts.
    """
    from models import db, Post  # noqa: F811 — real imports in production

    # Object-level authorization: filter by BOTH post_id AND current user's ownership.
    # This prevents IDOR (Insecure Direct Object Reference) attacks where an attacker
    # supplies another user's post_id.
    post = Post.query.filter_by(id=post_id, author_id=current_user.id).first()

    if post is None:
        # Return 404 regardless of whether the post exists but belongs to someone else,
        # or doesn't exist at all. This avoids enumeration attacks.
        abort(404, description="Post not found.")

    db.session.delete(post)
    db.session.commit()

    return jsonify({"message": "Post deleted successfully.", "post_id": post_id}), 200